--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -720,6 +720,109 @@
   for (let i = 0; i < 4; i++) {
     ctx.fillStyle = '#7f8c8d'; ctx.fillRect(x + w * 0.12 + i * 12, y + h * 0.12 + 4, 2, 10 + i * 2);
   }
+}
+
+// ─── Decorative Props ─────────────────────────────────────────────
+
+function drawTapestry(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string) {
+  ctx.fillStyle = '#3a2a40';
+  ctx.fillRect(x, y, w, h);
+  ctx.fillStyle = color;
+  for (let i = 2; i < w - 2; i += 4) {
+    ctx.fillRect(x + i, y + 2, 2, h - 4);
+  }
+  ctx.fillStyle = '#2a1a30';
+  ctx.fillRect(x, y, 2, h);
+  ctx.fillRect(x + w - 2, y, 2, h);
+}
+
+function drawWallShield(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  ctx.moveTo(x + 8, y);
+  ctx.lineTo(x + 16, y + 4);
+  ctx.lineTo(x + 16, y + 16);
+  ctx.lineTo(x + 8, y + 22);
+  ctx.lineTo(x, y + 16);
+  ctx.lineTo(x - 8, y + 4);
+  ctx.closePath();
+  ctx.fill();
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(x + 6, y + 8, 4, 3);
+  ctx.fillRect(x + 8, y + 4, 2, 12);
+}
+
+function drawCandelabra(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  ctx.fillStyle = '#6a4a20';
+  ctx.fillRect(x + 6, y + 8, 4, 8);
+  ctx.fillRect(x + 4, y + 12, 8, 2);
+  ctx.fillRect(x + 2, y + 10, 12, 2);
+  ctx.fillStyle = '#f0e68c';
+  ctx.beginPath();
+  ctx.ellipse(x + 6, y + 6, 2, 4, 0, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.beginPath();
+  ctx.ellipse(x + 10, y + 6, 2, 4, 0, 0, Math.PI * 2);
+  ctx.fill();
+}
+
+function drawBarrel(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  ctx.fillStyle = '#8b5a2b';
+  ctx.fillRect(x, y, 12, 16);
+  ctx.fillStyle = '#5a3a18';
+  ctx.fillRect(x + 2, y + 2, 8, 12);
+  ctx.fillRect(x + 1, y + 1, 10, 2);
+  ctx.fillRect(x + 1, y + 13, 10, 2);
+}
+
+function drawCrate(ctx: CanvasRenderingContext2D, x: number, y: number) {
+  ctx.fillStyle = '#a0522d';
+  ctx.fillRect(x, y, 14, 14);
+  ctx.fillStyle = '#6b3a1a';
+  ctx.fillRect(x + 2, y + 2, 10, 10);
+  ctx.fillRect(x + 6, y + 2, 2, 10);
+  ctx.fillRect(x + 2, y + 6, 10, 2);
+}
+
+function drawRug(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, color: string) {
+  ctx.fillStyle = '#2c3040';
+  ctx.fillRect(x, y, w, h);
+  ctx.fillStyle = color;
+  ctx.fillRect(x + 2, y + 2, w - 4, h - 4);
+  ctx.fillStyle = '#1a1e28';
+  ctx.fillRect(x + 4, y + 4, w - 8, h - 8);
+}
+
+// ─── Add Props to Rooms ───────────────────────────────────────────
+
+function drawThroneRoom(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  const tx = x + w * 0.38, ty = y + h * 0.18, tw = w * 0.24, th = h * 0.35;
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(tx, ty, tw, th);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(tx + 2, ty + 2, tw - 4, th - 4);
+  ctx.fillStyle = '#8b1a1a'; ctx.fillRect(tx + 3, ty + th * 0.55, tw - 6, th * 0.35);
+  ctx.fillStyle = '#a02525'; ctx.fillRect(tx + 5, ty + th * 0.58, tw - 10, th * 0.28);
+  ctx.fillStyle = P.gold[3];
+  ctx.fillRect(tx, ty, tw, 3); ctx.fillRect(tx, ty, 3, th); ctx.fillRect(tx + tw - 3, ty, 3, th);
+  ctx.fillRect(tx + tw * 0.25, ty + 8, tw * 0.5, 3);
+  ctx.fillRect(tx + tw * 0.3, ty + 5, 3, 6);
+  ctx.fillRect(tx + tw * 0.45, ty + 3, 3, 8);
+  ctx.fillRect(tx + tw * 0.6, ty + 5, 3, 6);
+  ctx.fillStyle = '#4a2810';
+  ctx.fillRect(tx - 4, ty + th * 0.5, 6, th * 0.4); ctx.fillRect(tx + tw - 2, ty + th * 0.5, 6, th * 0.4);
+  ctx.fillStyle = P.gold[2];
+  ctx.fillRect(tx - 4, ty + th * 0.5, 6, 2); ctx.fillRect(tx + tw - 2, ty + th * 0.5, 6, 2);
+  drawBanner(ctx, x + w * 0.08, y + 4, 18, 38, '#8b1515', P.gold[3]);
+  drawBanner(ctx, x + w * 0.82, y + 4, 18, 38, '#8b1515', P.gold[3]);
+  drawTorch(ctx, x + w * 0.02, y + h * 0.15, frame);
+  drawTorch(ctx, x + w * 0.92, y + h * 0.15, frame);
+  // Add wall decorations
+  drawTapestry(ctx, x + w * 0.15, y + h * 0.1, 20, 30, '#6a2a2a');
+  drawWallShield(ctx, x + w * 0.7, y + h * 0.2);
+  drawCandelabra(ctx, x + w * 0.5, y + h * 0.3);
+  drawRug(ctx, x + w * 0.3, y + h * 0.8, 40, 20, '#8b0000');
+}
+
+function drawWarRoom(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  const rx = x + w * 0.03, ry = y + h * 0.08;
+  ctx.fillStyle = '#3a2010'; ctx.fillRect(rx, ry, w * 0.12, h * 0.32);
+  ctx.fillStyle = '#4a2a14'; ctx.fillRect(rx + 2, ry + 2, w * 0.12 - 4, h * 0.32 - 4);
+  for (let i = 0; i < 3; i++) {
+    const sx = rx + 4 + i * 8;
+    ctx.fillStyle = '#9a9aaa'; ctx.fillRect(sx, ry + 4, 2, h * 0.24);
+    ctx.fillStyle = '#5a3a18'; ctx.fillRect(sx - 1, ry + h * 0.22, 4, 4);
+    ctx.fillStyle = P.gold[2]; ctx.fillRect(sx - 2, ry + h * 0.2, 6, 2);
+  }
+  // Shield
+  ctx.fillStyle = '#2a4080';
+  ctx.beginPath();
+  const shx = rx + w * 0.14 + 10;
+  ctx.moveTo(shx, ry + 2); ctx.lineTo(shx + 10, ry + 6); ctx.lineTo(shx + 10, ry + 20);
+  ctx.lineTo(shx + 5, ry + 26); ctx.lineTo(shx, ry + 20); ctx.lineTo(shx - 10, ry + 6);
+  ctx.closePath(); ctx.fill();
+  ctx.fillStyle = P.gold[3]; ctx.fillRect(shx - 2, ry + 10, 6, 2); ctx.fillRect(shx, ry + 6, 2, 14);
+
+  // Training dummy
+  const dx = x + w * 0.78, dy = y + h * 0.35;
+  ctx.fillStyle = '#6a5a40'; ctx.fillRect(dx + 6, dy, 4, 30);
+  ctx.fillStyle = '#8a7a58'; ctx.fillRect(dx, dy + 4, 16, 4); ctx.fillRect(dx + 3, dy - 2, 10, 8);
+  ctx.fillStyle = '#a0906a'; ctx.beginPath(); ctx.arc(dx + 8, dy - 2, 6, 0, Math.PI * 2); ctx.fill();
+
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(x + w * 0.3, y + h * 0.55, w * 0.4, h * 0.1);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(x + w * 0.31, y + h * 0.56, w * 0.38, h * 0.08);
+  drawTorch(ctx, x + w * 0.5, y + h * 0.06, frame);
+  // Add props
+  drawWallShield(ctx, x + w * 0.15, y + h * 0.15);
+  drawWallShield(ctx, x + w * 0.65, y + h * 0.25);
+  drawTapestry(ctx, x + w * 0.4, y + 4, 18, 38, '#8b1515');
+  drawRug(ctx, x + w * 0.3, y + h * 0.75, 50, 20, '#4a2a2a');
+}
+
+function drawWorkshop(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  const bx = x + w * 0.1, by = y + h * 0.52;
+  ctx.fillStyle = '#4a2810'; ctx.fillRect(bx, by, w * 0.75, h * 0.1);
+  ctx.fillStyle = '#5c3418'; ctx.fillRect(bx + 2, by + 1, w * 0.75 - 4, h * 0.08);
+  ctx.fillStyle = '#3a1e08';
+  ctx.fillRect(bx + 2, by + h * 0.1, 4, h * 0.1);
+  ctx.fillRect(bx + w * 0.72, by + h * 0.1, 4, h * 0.1);
+  ctx.fillStyle = '#7f8c8d';
+  ctx.fillRect(bx + 10, by - 2, 3, 8); ctx.fillRect(bx + 20, by - 4, 2, 10);
+  ctx.fillStyle = '#5a3a18'; ctx.fillRect(bx + 8, by + 3, 7, 3);
+  ctx.fillStyle = '#7f8c8d'; ctx.fillRect(bx + 6, by + 1, 4, 3);
+  // Tool rack
+  ctx.fillStyle = '#3a2010'; ctx.fillRect(x + w * 0.1, y + h * 0.12, w * 0.25, 4);
+  for (let i = 0; i < 4; i++) {
+    ctx.fillStyle = '#7f8c8d'; ctx.fillRect(x + w * 0.12 + i * 12, y + h * 0.12 + 4, 2, 10 + i * 2);
+  }
+  // Add barrels and crates
+  drawBarrel(ctx, x + w * 0.6, y + h * 0.55);
+  drawCrate(ctx, x + w * 0.7, y + h * 0.6);
+  drawBarrel(ctx, x + w * 0.5, y + h * 0.6);
+  drawCrate(ctx, x + w * 0.4, y + h * 0.55);
+}
+
+function drawScriptorium(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Existing code omitted for brevity
+  // Add extra bookshelves as props
+  ctx.fillStyle = '#5a3a18';
+  ctx.fillRect(x + w * 0.1, y + h * 0.3, 12, 40);
+  ctx.fillRect(x + w * 0.25, y + h * 0.3, 12, 40);
+  ctx.fillRect(x + w * 0.4, y + h * 0.3, 12, 40);
+  ctx.fillRect(x + w * 0.55, y + h * 0.3, 12, 40);
+}
+
